import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.B8zgMDLd.js";const h=JSON.parse('{"title":"Supported Platforms","description":"","frontmatter":{},"headers":[],"relativePath":"reference/supported-platforms.md","filePath":"reference/supported-platforms.md"}'),p={name:"reference/supported-platforms.md"};function l(d,t,i,s,n,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="supported-platforms" tabindex="-1">Supported Platforms <a class="header-anchor" href="#supported-platforms" aria-label="Permalink to &quot;Supported Platforms&quot;">​</a></h1><p>Tolaria is a desktop app built with Tauri. Releases currently target macOS, Windows, and Linux.</p><table tabindex="0"><thead><tr><th>Platform</th><th>Current support</th><th>Notes</th></tr></thead><tbody><tr><td>macOS</td><td>Primary</td><td>Main development and QA target. Apple Silicon and Intel artifacts are published.</td></tr><tr><td>Windows</td><td>Supported, early</td><td>NSIS installers and signed updater bundles are published. Menu, shell-path, and credential-helper behavior receive platform-specific fixes as they appear.</td></tr><tr><td>Linux</td><td>Supported, early</td><td>AppImage and deb artifacts are published. Behavior can depend on distro WebKitGTK packages, Wayland/X11 details, and input-method setup.</td></tr></tbody></table><h2 id="support-policy" tabindex="-1">Support Policy <a class="header-anchor" href="#support-policy" aria-label="Permalink to &quot;Support Policy&quot;">​</a></h2><p>Primary support means the platform is part of normal development and release validation. Supported, early means release artifacts exist and the app is expected to work, but platform-specific bugs can take longer to diagnose than macOS issues.</p><h2 id="reporting-platform-bugs" tabindex="-1">Reporting Platform Bugs <a class="header-anchor" href="#reporting-platform-bugs" aria-label="Permalink to &quot;Reporting Platform Bugs&quot;">​</a></h2><p>Include:</p><ul><li>Tolaria version.</li><li>Operating system and version.</li><li>CPU architecture.</li><li>Whether the vault is local-only or connected to a remote.</li><li>Steps to reproduce.</li></ul>',8)])])}const m=e(p,[["render",l]]);export{h as __pageData,m as default};
